const GEMINI_KEYS = [
  { name: 'eilinaire',       key: $env.EILINAIRE_GOOGLE_API_KEY },
  { name: 'jooshdathumlong', key: $env.JOOSHDATHUMLONG_GOOGLE_API_KEY },
  { name: 'mahittisak',      key: $env.MAHITTISAK_GOOGLE_API_KEY },
  { name: 'sunsetsol',       key: $env.SUNSETSOL_GOOGLE_API_KEY },
  { name: 'rlie',            key: $env.RLIE_GOOGLE_API_KEY },
  { name: 'peabantid',       key: $env.PEABANTID_GOOGLE_API_KEY },
].filter(k => k.key);

const GEMINI_MODELS = ['gemini-2.0-flash', 'gemini-2.0-flash-lite', 'gemini-flash-lite-latest'];

const MATRIX = {
  'CREATIVE':      { primary: 'claude-sonnet-4-6',   fallback: 'gpt-4o' },
  'PERSONAL':      { primary: 'claude-sonnet-4-6',   fallback: 'gpt-4o' },
  'JOB.MARKETING': { primary: 'gemini-2.0-flash',    fallback: 'gemini-2.0-flash-lite' },
  'JOB.OPS':       { primary: 'gemini-2.0-flash',    fallback: 'gemini-2.0-flash-lite' },
  'LONG-CONTEXT':  { primary: 'gemini-2.0-flash',    fallback: 'claude-sonnet-4-6' },
  'default':       { primary: 'gemini-2.0-flash',    fallback: 'gemini-2.0-flash-lite' }
};
const AGENT_MAP = { JOB: 'jeff', PERSONAL: 'eilinaire', CREATIVE: 'ego_era' };

const input    = $input.first().json;
const pillar   = (input.pillar || 'default').toUpperCase();
const reduced  = input.reduced_mode === true;
const throttled = {};

for (const row of $('Check Rate Limits').all()) {
  if (row.json.is_throttled) throttled[row.json.provider] = true;
}

const matrixKey = Object.keys(MATRIX).find(k => pillar.startsWith(k)) || 'default';
let selectedModel = reduced ? 'gemini-2.0-flash-lite' : MATRIX[matrixKey].primary;
if (throttled[selectedModel]) {
  selectedModel = GEMINI_MODELS.find(m => !throttled[m]) || MATRIX[matrixKey].fallback;
}

// Round-robin key by minute
const keyIndex = Math.floor(Date.now() / 60000) % GEMINI_KEYS.length;
const geminiKey = GEMINI_KEYS[keyIndex] || {};

const topPillar = pillar.split('.')[0];
const assignedAgent = AGENT_MAP[topPillar] || 'jeff';

return [{ json: {
  assigned_agent:  assignedAgent,
  selected_model:  selectedModel,
  gemini_key_name: geminiKey.name || 'none',
  gemini_api_key:  geminiKey.key  || '',
  pillar:          pillar,
  reduced_mode:    reduced,
  message:         input.message || '',
  routed_at:       new Date().toISOString()
}}];

